sql:
SELECT f.*, u.update_date, u.update_description 
FROM filings f 
LEFT JOIN filing_updates u ON f.filing_id = u.filing_id;

SELECT filing_id, SUM(file_size) AS total_file_size 
FROM file_attachments 
GROUP BY filing_id;

external_knowledge:
- "identities" correspond to the 'applicant_name';
- "official registration numbers" refer to the 'frn';
- "parent corporations" are represented by the 'parent_company_name';
- "earliest official registration numbers" mean ordering by 'frn' in ascending order.

sql:
SELECT applicants.applicant_name, industry_types.industry_type_name
FROM applicants
JOIN industry_types ON applicants.industry_type_id = industry_types.industry_type_id;

SELECT *
FROM users
WHERE user_id IN (SELECT update_user_id FROM filing_updates);

SELECT applicant_id, frn, applicant_name, company_address, contact_email, phone_number, website_url, parent_company_id, industry_type_id
FROM applicants
WHERE frn = (SELECT MAX(frn) FROM applicants);

SELECT COUNT(*) AS total_updates
FROM filing_updates
WHERE filing_id = (SELECT filing_id FROM filings WHERE file_number = 'Specific File Number');

SELECT AVG(file_size) AS average_file_size
FROM file_numbers
WHERE file_type_id = 'specific_file_type_id';

SELECT COUNT(DISTINCT a.applicant_id) AS unique_applicants_count
FROM applicants a
JOIN filings f ON a.applicant_id = f.applicant_id;

external_knowledge:
- "documents" refers to the files associated with each filing;
- "typical size" refers to the average file size;
- "total count" refers to the number of filings;
- "each type of filing status" refers to different statuses like 'Pending', 'Approved', 'Rejected', etc.
